export function downloadMapDisplayApiContext() {
  const blob = new Blob([MAP_DISPLAY_API_CLAUDE_CONTEXT], { type: 'text/markdown;charset=utf-8' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = 'tomtom-map-display-api.md';
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}
